    ProdLogger.includeSensitive = includeSensitive;
    if (sink != null) ProdLogger.sink = sink;

    FlutterError.onError = (FlutterErrorDetails details) {
      ProdLogger.e('FLUTTER', 'FlutterError', details.exception, details.stack);
      FlutterError.presentError(details);
    };

    PlatformDispatcher.instance.onError = (Object error, StackTrace stack) {
      ProdLogger.e('DART', 'Uncaught zone/platform error', error, stack);
      return false;
    };
  }

  static Future<void> runLogged(Future<void> Function() appMain) async {
    await runZonedGuarded(() async {
      await appMain();
    }, (e, st) {
      ProdLogger.e('ZONE', 'Uncaught zoned error', e, st);
    });
  }
}